#Given two strings s and t of equal length, the Hamming distance between s and t , denoted dH(s,t)
s=""
t=""
def hamming_distance(s,t):
    Distance=0
    for i in range(len(s)):
        if s[i]!=t[i]:
            Distance +=1
    return Distance

Distance = hamming_distance(s, t)
print(Distance)


